// ── Helper Functions ──────────────────────────────────────────────────────────

export function getTemplatesByCategory(category: TemplateCategory): LibraryTemplate[] {
    return templateLibrary.filter((t) => t.category === category);
}

export function getTemplatesByProgram(program: TemplateProgram): LibraryTemplate[] {
    return templateLibrary.filter((t) => t.program === program);
}

export function getFeaturedTemplates(): LibraryTemplate[] {
    return templateLibrary.filter((t) => t.isFeatured);
}

export function searchLibraryTemplates(query: string): LibraryTemplate[] {
    const lower = query.toLowerCase();
    return templateLibrary.filter(
        (t) =>
            t.name.toLowerCase().includes(lower) ||
            t.description.toLowerCase().includes(lower) ||
            t.tags.some((tag) => tag.toLowerCase().includes(lower)) ||
            t.program.toLowerCase().includes(lower),
    );
}

